import React, { useState, useEffect } from 'react';
import {
  Container,
  Typography,
  Box,
  Paper,
  Button,
  TextField,
  CircularProgress,
  Snackbar,
  Alert,
  Stack,
  Dialog,
  DialogActions,
  DialogContent,
  DialogContentText,
  DialogTitle,
  Divider,
  Fade,
} from '@mui/material';
import { useNavigate } from 'react-router-dom';
import PersonIcon from '@mui/icons-material/Person';
import PageHeader from '../../components/common/PageHeader';
import { useAuth } from '../../hooks/useAuth';

// Firebase Imports
import { db } from '../../firebaseConfig';
import { doc, getDoc, setDoc, deleteDoc } from 'firebase/firestore';
import {
  updateProfile,
  deleteUser,
  EmailAuthProvider,
  reauthenticateWithCredential,
  updatePassword,
} from 'firebase/auth';
import SuspenseFallback from '../../components/common/SuspenseFallback';

const AdminProfile = () => {
  const { user, loading: authLoading, logout } = useAuth();
  const navigate = useNavigate();

  const [profileData, setProfileData] = useState({
    displayName: '',
    bio: '',
  });
  const [loadingProfile, setLoadingProfile] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [snackbar, setSnackbar] = useState({
    open: false,
    message: '',
    severity: 'success',
  });
  const [confirmDeleteOpen, setConfirmDeleteOpen] = useState(false);
  const [reauthenticateOpen, setReauthenticateOpen] = useState(false);
  const [reauthPassword, setReauthPassword] = useState('');
  const [reauthError, setReauthError] = useState('');

  const [currentPassword, setCurrentPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmNewPassword, setConfirmNewPassword] = useState('');
  const [passwordChangeLoading, setPasswordChangeLoading] = useState(false);
  const [passwordChangeError, setPasswordChangeError] = useState('');

  useEffect(() => {
    if (!authLoading && !user) {
      navigate('/admin/login');
    }
  }, [user, authLoading, navigate]);

  useEffect(() => {
    const fetchProfile = async () => {
      if (user) {
        try {
          setLoadingProfile(true);
          const userId = user.uid || user.id;
          if (!userId) {
            throw new Error('User ID is missing');
          }
          const profileRef = doc(db, 'authorProfiles', userId);
          const docSnap = await getDoc(profileRef);

          if (docSnap.exists()) {
            const data = docSnap.data();
            setProfileData({
              displayName: data.displayName || user.displayName || '',
              bio: data.bio || '',
            });
          } else {
            setProfileData({
              displayName: user.displayName || '',
              bio: '',
            });
          }
        } catch (error) {
          console.error('Error fetching author profile:', error);
          setSnackbar({
            open: true,
            message: `Error loading profile: ${error.message}`,
            severity: 'error',
          });
          setProfileData({
            displayName: user.displayName || '',
            bio: '',
          });
        } finally {
          setLoadingProfile(false);
        }
      }
    };

    if (!authLoading && user) {
      fetchProfile();
    }
  }, [user, authLoading]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setProfileData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSaveProfile = async () => {
    if (!user) return;
    setIsSubmitting(true);
    try {
      await updateProfile(user, {
        displayName: profileData.displayName,
      });

      const userId = user.uid || user.id;
      const profileRef = doc(db, 'authorProfiles', userId);
      await setDoc(profileRef, {
        displayName: profileData.displayName,
        bio: profileData.bio
      }, { merge: true });

      setSnackbar({
        open: true,
        message: 'Profile updated successfully!',
        severity: 'success',
      });
    } catch (error) {
      console.error('Error saving profile:', error);
      setSnackbar({
        open: true,
        message: `Error saving profile: ${error.message}`,
        severity: 'error',
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleChangePassword = async () => {
    if (!user) return;
    setPasswordChangeLoading(true);
    setPasswordChangeError('');

    if (!currentPassword || !newPassword || !confirmNewPassword) {
      setPasswordChangeError('All password fields are required.');
      setPasswordChangeLoading(false);
      return;
    }

    if (newPassword !== confirmNewPassword) {
      setPasswordChangeError('New password and confirm password do not match.');
      setPasswordChangeLoading(false);
      return;
    }

    if (newPassword.length < 6) {
      setPasswordChangeError(
        'New password must be at least 6 characters long.',
      );
      setPasswordChangeLoading(false);
      return;
    }

    try {
      const credential = EmailAuthProvider.credential(
        user.email,
        currentPassword,
      );
      await reauthenticateWithCredential(user, credential);

      await updatePassword(user, newPassword);

      setSnackbar({
        open: true,
        message: 'Password updated successfully!',
        severity: 'success',
      });
      setCurrentPassword('');
      setNewPassword('');
      setConfirmNewPassword('');
    } catch (error) {
      console.error('Error changing password:', error);
      let errorMessage = 'Failed to change password.';
      if (error.code === 'auth/wrong-password') {
        errorMessage = 'Incorrect current password.';
      } else if (error.code === 'auth/weak-password') {
        errorMessage =
          'Password is too weak. Please choose a stronger password.';
      } else if (error.code === 'auth/requires-recent-login') {
        errorMessage = 'Please log in again to update your password.';
      } else {
        errorMessage = `Error: ${error.message}`;
      }
      setPasswordChangeError(errorMessage);
    } finally {
      setPasswordChangeLoading(false);
    }
  };

  const handleDeleteProfileClick = () => {
    setConfirmDeleteOpen(true);
  };

  const handleConfirmDelete = async () => {
    setConfirmDeleteOpen(false);
    if (!user) return;

    try {
      const userId = user.uid || user.id;
      const profileRef = doc(db, 'authorProfiles', userId);
      await deleteDoc(profileRef);
      await deleteUser(user);

      setSnackbar({
        open: true,
        message: 'Profile and account deleted successfully!',
        severity: 'success',
      });
      logout();
    } catch (error) {
      console.error('Error deleting account:', error);
      if (error.code === 'auth/requires-recent-login') {
        setReauthenticateOpen(true);
      } else {
        setSnackbar({
          open: true,
          message: `Error deleting account: ${error.message}`,
          severity: 'error',
        });
      }
    }
  };

  const handleReauthenticate = async () => {
    setReauthError('');
    if (!user || !user.email || !reauthPassword) {
      setReauthError('Email and password are required.');
      return;
    }

    try {
      const credential = EmailAuthProvider.credential(
        user.email,
        reauthPassword,
      );
      await reauthenticateWithCredential(user, credential);
      setReauthenticateOpen(false);
      setReauthPassword('');
      handleConfirmDelete();
    } catch (error) {
      console.error('Re-authentication error:', error);
      setReauthError(`Re-authentication failed: ${error.message}`);
    }
  };

  if (authLoading) {
    return (
      <Container maxWidth="md" sx={{ py: 8, textAlign: 'center' }}>
        <CircularProgress />
      </Container>
    );
  }

  if (!user) {
    return null;
  }

  if (loadingProfile) {
    return (
      <Container maxWidth="md" sx={{ py: 8, textAlign: 'center' }}>
        <SuspenseFallback message="" />
      </Container>
    );
  }

  return (
    <Fade in={!loadingProfile} timeout={1000}>
      <Container maxWidth="md" sx={{ py: 4 }}>
        <PageHeader
          title="My Author Profile"
          subtitle="Manage your public author information and account settings."
          icon={PersonIcon}
        />

        <Paper
          elevation={3}
          sx={{
            p: { xs: 2, md: 4 },
            mt: 3,
            borderRadius: 2,
            boxShadow: 3,
          }}
        >
          <Typography variant="h6" gutterBottom color="primary.main">
            Profile Details
          </Typography>
          <Stack spacing={3} sx={{ mb: 4 }}>
            {/* Added Email Field (Read-Only) */}
            <TextField
              label="Email Address"
              variant="outlined"
              fullWidth
              value={user.email || ''}
              disabled
              helperText="The email address associated with your account."
            />
            <TextField
              label="Display Name"
              name="displayName"
              variant="outlined"
              fullWidth
              value={profileData.displayName}
              onChange={handleChange}
              helperText="This name will appear on your articles."
            />
            <TextField
              label="Bio"
              name="bio"
              variant="outlined"
              fullWidth
              multiline
              rows={4}
              value={profileData.bio}
              onChange={handleChange}
              helperText="Tell readers a bit about yourself."
            />
          </Stack>
          <Stack direction="row" spacing={2} justifyContent="flex-end">
            <Button
              variant="contained"
              color="primary"
              onClick={handleSaveProfile}
              disabled={isSubmitting}
              startIcon={
                isSubmitting && <CircularProgress size={20} color="inherit" />
              }
            >
              {isSubmitting ? 'Saving...' : 'Save Profile'}
            </Button>
          </Stack>

          <Divider sx={{ my: 4, borderColor: 'divider' }} />

          <Typography variant="h6" gutterBottom color="primary.main">
            Change Password
          </Typography>
          <Typography variant="body2" sx={{ mb: 2, color: 'text.secondary' }}>
            Use your email ({user.email}) as your username for normal login.
          </Typography>
          <Stack spacing={3} sx={{ mb: 4 }}>
            <TextField
              label="Current Password"
              type="password"
              variant="outlined"
              fullWidth
              value={currentPassword}
              onChange={(e) => setCurrentPassword(e.target.value)}
            />
            <TextField
              label="New Password"
              type="password"
              variant="outlined"
              fullWidth
              value={newPassword}
              onChange={(e) => setNewPassword(e.target.value)}
              helperText="Minimum 6 characters."
            />
            <TextField
              label="Confirm New Password"
              type="password"
              variant="outlined"
              fullWidth
              value={confirmNewPassword}
              onChange={(e) => setConfirmNewPassword(e.target.value)}
              error={!!passwordChangeError}
              helperText={passwordChangeError}
            />
          </Stack>
          <Stack direction="row" spacing={2} justifyContent="flex-end">
            <Button
              variant="contained"
              color="secondary"
              onClick={handleChangePassword}
              disabled={passwordChangeLoading}
              startIcon={
                passwordChangeLoading && (
                  <CircularProgress size={20} color="inherit" />
                )
              }
            >
              {passwordChangeLoading ? 'Changing...' : 'Change Password'}
            </Button>
          </Stack>

          <Divider sx={{ my: 4, borderColor: 'divider' }} />
          
          <Typography variant="h6" color="error" gutterBottom>
            Danger Zone
          </Typography>
          <Typography variant="body2" sx={{ mb: 2, color: 'text.secondary' }}>
            Permanently delete your author profile and account. This action
            cannot be undone.
          </Typography>
          <Button
            variant="outlined"
            color="error"
            onClick={handleDeleteProfileClick}
            disabled={isSubmitting}
          >
            Delete My Account
          </Button>
        </Paper>

        <Snackbar
          open={snackbar.open}
          autoHideDuration={5000}
          onClose={() => setSnackbar({ ...snackbar, open: false })}
        >
          <Alert
            onClose={() => setSnackbar({ ...snackbar, open: false })}
            severity={snackbar.severity}
            variant="filled"
          >
            {snackbar.message}
          </Alert>
        </Snackbar>

        <Dialog
          open={confirmDeleteOpen}
          onClose={() => setConfirmDeleteOpen(false)}
        >
          <DialogTitle>{'Confirm Account Deletion'}</DialogTitle>
          <DialogContent>
            <DialogContentText>
              Are you absolutely sure you want to delete your account? All your
              profile data will be removed, and you will no longer be able to
              log in. This action cannot be undone.
            </DialogContentText>
          </DialogContent>
          <DialogActions>
            <Button onClick={() => setConfirmDeleteOpen(false)}>Cancel</Button>
            <Button onClick={handleConfirmDelete} color="error" autoFocus>
              Delete Account
            </Button>
          </DialogActions>
        </Dialog>

        <Dialog
          open={reauthenticateOpen}
          onClose={() => setReauthenticateOpen(false)}
        >
          <DialogTitle>{'Re-authenticate to Delete Account'}</DialogTitle>
          <DialogContent>
            <DialogContentText>
              For security reasons, you must re-authenticate to delete your
              account. Please enter your password.
            </DialogContentText>
            <TextField
              autoFocus
              margin="dense"
              label="Password"
              type="password"
              fullWidth
              variant="standard"
              value={reauthPassword}
              onChange={(e) => setReauthPassword(e.target.value)}
              error={!!reauthError}
              helperText={reauthError}
            />
          </DialogContent>
          <DialogActions>
            <Button onClick={handleReauthenticate} color="primary">
              Re-authenticate
            </Button>
            <Button onClick={() => setReauthenticateOpen(false)}>Cancel</Button>
          </DialogActions>
        </Dialog>
      </Container>
    </Fade>
  );
};

export default AdminProfile;